import { EmailJSResponseStatus } from '@emailjs/browser';
import style from './Contact.module.css'
import { Link } from 'react-router-dom';

function Contact() {
    const btn = document.getElementsById('button');

    document.getElementById('email-form').addEventListener
    ('submit', function(event) {
        event.preventDefault();

        btn.value = 'sending...';

        const serviceID = '';
        const templateID = '';

        EmailJSResponseStatus.sendForm(serviceID, templateID, this)
        .then(() => {
            btn.value = 'send Email';
            alert('Email Berhasil Terkirim');
        }, (err) => {
            btn.value = 'send Email'
            alert(JSON.stringify(err));
        });
    });

    return (
        <div className={style.contactpage}>
            <header className={style.header}>
                <h1 className={style.logo}>MSHDQ</h1>
                <nav className={style.nav}>
                    <Link to="/" className={style.link}>HOME</Link>
                    <Link to="/about" className={style.link}>ABOUT</Link>
                    <Link to="/service" className={style.link}>SERVICE</Link>
                    <Link to="/portofolio" className={style.link}>PORTOFOLIO</Link>
                    <Link to="/blog" className={style.link}>BLOG</Link>
                    <Link to="/contact" className={style.link}>CONTACT</Link>
                </nav>
            </header>

            <div>
                <section className={style.contact_section}>
                    <h1>Contact Me</h1>
                    <p>If you’d like to collaborate or just say hi, feel free to send a message!</p>

                    <form className={style.contact_form} >
                        <input type="text" name="Name" placeholder="Your Name" required />
                        <input type="email" name="to_email" id="to_email" placeholder="Your Email" required />
                        <textarea name="Message" placeholder="Your Message" rows="6" required></textarea>
                        <button type="submit">Send Message</button>
                    </form>
                </section>
            </div>

            <script
                src="https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js">
            </script>

            <script>
                emailjs.init('K4NTdgElNQ3N4cQ9H');
            </script>

            <footer className={style.footer}>
                &copy; 2025 MSHDQ. All rights reserved.
            </footer>
        </div>
    )
}

export default Contact;
